function bgImgC = fDnnBg(scnNDir,camClb)% Return cell of backgrounud images for DNNa magspec%% bgImgC = fDnnBg(scnNDir,camClb)%% bgImgC: cell of background image%% scnNDir: scan # directory% camClb: camera calibration for ROI%%% Written by Kei Nakamura% 2018/2/8 ver.1: created% 2018/11/19 ver.1b: camera name in calibration% %% main body% name{1} = 'HTT-MagCam-01';% name{2} = 'HTT-MagCam-02';% name{3} = 'HTT-MagCam-03';% name{4} = 'HTT-MagCam-04';name{1} = char(camClb(1).name);name{2} = char(camClb(2).name);name{3} = char(camClb(3).name);name{4} = char(camClb(4).name);for i=1:4    img = fAvrgImg(scnNDir,name{i});    bgImgC{i} = img(camClb(i).ySt:camClb(i).yEd,camClb(i).xSt:camClb(i).xEd);   % analysis roiend% figure(100)% subplot(4,1,1)% pcolor(bgImgC{1})% shading interp% colorbar% caxis([0 10])% subplot(4,1,2)% pcolor(bgImgC{2})% shading interp% colorbar% caxis([0 10])% subplot(4,1,3)% pcolor(bgImgC{3})% shading interp% colorbar% caxis([0 10])% subplot(4,1,4)% pcolor(bgImgC{4})% shading interp% colorbar% caxis([0 10])
